import{_ as t,o as r,c as n,a2 as s}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"메뉴 관리 화면 lego UI/UX 정합","description":"","frontmatter":{"title":"메뉴 관리 화면 lego UI/UX 정합","feature_id":"015","status":"done","created":"2026-06-07 12:40 (KST)","date":"2026-06-07T00:00:00.000Z","tags":["frontend","backend","admin","menu","ui-ux","vue","vuetify","feature-006","feature-004"]},"headers":[],"relativePath":"specs/015-lego-menu-parity/spec.md","filePath":"specs/015-lego-menu-parity/spec.md","lastUpdated":null}'),e={name:"specs/015-lego-menu-parity/spec.md"};function i(l,o,a,g,c,u){return r(),n("div",null,[...o[0]||(o[0]=[s('<h1 id="spec-메뉴-관리-화면-lego-ui-ux-정합" tabindex="-1">Spec: 메뉴 관리 화면 lego UI/UX 정합 <a class="header-anchor" href="#spec-메뉴-관리-화면-lego-ui-ux-정합" aria-label="Permalink to &quot;Spec: 메뉴 관리 화면 lego UI/UX 정합&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>feature 006(관리자 콘솔)에서 전반적인 디자인은 기준 소스 <code>C:/ax/lego</code> 에 맞췄지만, <strong>메뉴 관리 기능</strong>의 화면 구성·상호작용·데이터 모델이 lego 와 여전히 <strong>완전히 다르다.</strong></p><ul><li><strong>현재(006/004)</strong>: 메뉴 관리가 화면 1장. 평면 표(트리를 들여쓰기로 펼친 한 테이블)에서 메뉴명·유형·경로를 보여주고, 같은 표에 역할을 골라 <code>보기/실행</code> 두 권한 체크박스를 인라인으로 편집한다. 정렬 변경·계층 조작 수단이 없고, 메뉴 코드·컴포넌트·세분 권한이 없다.</li><li><strong>lego(기준)</strong>: 메뉴 관리가 <strong>두 개의 독립 화면</strong>이다. <ol><li><strong>메뉴 트리 관리</strong> — 좌측 인터랙티브 트리(펼침/접기, 레벨 표시, 드래그앤드롭 정렬, 위/아래 이동, 숨김 표시, hover 액션) + 우측 선택 노드 편집 패널(master-detail). 메뉴 코드·컴포넌트·표시 여부까지 편집.</li><li><strong>메뉴 권한</strong> — 역할을 고르면 메뉴×권한(읽기/생성/수정/삭제/Extra1~5 = 9종) 매트릭스를 표로 편집하는 별도 화면.</li></ol></li></ul><p>실무자가 메뉴 계층을 만들고 순서를 바꾸고 세분 권한을 부여하는 <strong>작업 경험과 권한 모델이 기준과 달라</strong>, 같은 제품군에서 화면을 오갈 때 학습 비용·이질감·기능 공백이 크다. 이 기능은 메뉴 관리의 <strong>화면·상호작용·데이터 모델·권한 모델</strong>을 lego 와 동일하게 맞춘다.</p><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><p>관리자 콘솔의 <strong>메뉴 관리 영역 전체</strong>(프론트 + 이를 뒷받침하는 백엔드)를 lego 와 동일한 작업 경험·모델로 재구성한다.</p><ul><li><strong>메뉴 트리 관리 화면(master-detail)</strong><ul><li>좌측: 계층 <strong>트리</strong> — 노드별 펼침/접기, 깊이별 레벨 표시(들여쓰기·레벨 색/뱃지), 숨김(비표시) 메뉴의 시각적 구분, 노드 hover 시 액션(상위 기준 위로/아래로 이동, 하위 추가), <strong>드래그앤드롭으로 같은 상위 안에서 순서 변경</strong>, 최상위 추가.</li><li>우측: 선택한 노드의 <strong>편집 패널</strong> — 상위 메뉴·유형(그룹/메뉴)·메뉴명·<strong>메뉴 코드</strong>· 경로·<strong>컴포넌트</strong>·아이콘(미리보기)·정렬·<strong>표시 여부 스위치</strong> 폼 + 저장/초기화. 미선택 시 안내(빈 상태).</li><li>새 메뉴 추가 다이얼로그, 삭제 확인(하위 동반 삭제 경고).</li></ul></li><li><strong>메뉴 권한 화면(별도)</strong><ul><li>역할 선택 → 메뉴 목록 × <strong>세분 권한(읽기/생성/수정/삭제/Extra1~5)</strong> 매트릭스를 체크박스로 편집 → 저장.</li><li>역할 관리 화면에서 특정 역할로 <strong>딥링크 진입</strong>(역할 사전 선택).</li></ul></li><li><strong>백엔드(004) 확장</strong> — 위 경험을 뒷받침하도록 메뉴/권한 모델·API 를 lego 수준으로 확장: <ul><li>메뉴에 <strong>menuCode·component·visible(표시 여부)</strong> 개념 추가(현행 필드와 정합).</li><li>역할-메뉴 권한을 <strong>다종 플래그(읽기/생성/수정/삭제/Extra1~5)</strong> 모델로 확장.</li><li><strong>순서 변경 배치 API</strong>(형제 노드 sortOrder 일괄 갱신) 추가.</li></ul></li><li><strong>시각 일관성</strong>: 이미 이식된 lego 테마/컴포넌트(카드·테이블·칩·라운드)를 그대로 따른다.</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>메뉴 관리 <strong>외</strong> 화면(사용자·역할·부서·대시보드·프로필)은 이미 정합 완료 — 대상 아님.</li><li>메뉴 외 도메인의 권한·감사·결재 등 다른 백엔드 기능 변경.</li><li>i18n 다국어 문구(한국어 1차 유지).</li><li>기존 메뉴 접근통제(인증·역할) 정책 자체의 변경(권한 <strong>모델 확장</strong>은 포함하되, 통제 원칙·로그인 흐름은 그대로).</li></ul><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-07" tabindex="-1">Session 2026-06-07 <a class="header-anchor" href="#session-2026-06-07" aria-label="Permalink to &quot;Session 2026-06-07&quot;">​</a></h3><ul><li>Q: lego 메뉴 관리와의 정합 깊이(백엔드 변경 범위)는? → A: <strong>B — 완전 정합 + 백엔드 확장.</strong> menuCode·component·visible·9종 권한 매트릭스· reorder 배치 API 까지 백엔드(004)에 추가해 필드·권한 모델까지 lego 와 동일하게 맞춘다.</li><li>Q: 권한 매트릭스 컬럼 수는? → A: lego 동일 <strong>다종(읽기/생성/수정/삭제/Extra1~5)</strong>.</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>계층 구성</strong>: 관리자가 메뉴 트리 화면에서 &quot;최상위 추가&quot;로 그룹을 만들고, 그 노드의 &quot;하위 추가&quot;로 자식 메뉴를 더한다. 트리에서 노드를 펼치고 접어 구조를 한눈에 본다.</li><li><strong>순서 변경</strong>: 관리자가 같은 상위 아래 형제 메뉴를 <strong>드래그앤드롭</strong>하거나 위/아래 이동 버튼으로 순서를 바꾼다. 변경은 저장되고 좌측 네비게이션 노출 순서에 반영된다.</li><li><strong>노드 편집</strong>: 관리자가 좌측에서 노드를 선택하면 우측 패널에 그 노드 속성(코드·경로· 컴포넌트·아이콘·표시 여부 등)이 채워지고, 고쳐 저장한다. 잘못된 입력은 검증으로 막힌다.</li><li><strong>숨김/표시</strong>: 관리자가 특정 메뉴를 비표시로 두면 트리에서 시각적으로 구분되고, 사용자 네비게이션에서는 노출되지 않는다.</li><li><strong>세분 권한 매트릭스</strong>: 관리자가 메뉴 권한 화면에서 역할을 고르면 메뉴×권한(읽기/생성/ 수정/삭제/Extra1~5) 표가 뜨고, 체크박스로 권한을 조정해 저장한다. 역할 관리에서 &quot;권한 편집&quot;으로 진입하면 해당 역할이 미리 선택돼 있다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="기능-functional" tabindex="-1">기능 (Functional) <a class="header-anchor" href="#기능-functional" aria-label="Permalink to &quot;기능 (Functional)&quot;">​</a></h3><ul><li><strong>FR-1 (트리 master-detail)</strong>: 메뉴 관리 화면은 좌측 계층 트리 + 우측 편집 패널의 2분할 구성을 제공한다. 노드 선택 시 우측에 해당 노드 속성이 로드된다.</li><li><strong>FR-2 (펼침/접기·레벨 표시)</strong>: 트리 노드는 자식이 있으면 펼치고 접을 수 있으며, 깊이에 따라 들여쓰기와 레벨 구분(색/뱃지 등)이 드러난다.</li><li><strong>FR-3 (순서 변경)</strong>: 같은 상위 아래 형제 메뉴의 순서를 <strong>드래그앤드롭</strong> 및 위/아래 이동으로 바꿀 수 있고, 결과가 저장·반영된다(상위가 다른 노드 간 이동은 막는다). 백엔드는 <strong>순서 일괄 갱신</strong>을 지원한다.</li><li><strong>FR-4 (계층 편집)</strong>: 최상위/하위 메뉴를 추가하고, 노드를 수정하고, 삭제할 수 있다. 삭제 시 하위가 있으면 함께 삭제됨을 경고한다.</li><li><strong>FR-5 (확장 편집 폼)</strong>: 우측 패널 폼은 상위 메뉴·유형·메뉴명·<strong>메뉴 코드</strong>·경로· <strong>컴포넌트</strong>·아이콘(미리보기)·정렬·<strong>표시 여부</strong>를 편집하며, 필수값 검증 후 저장한다.</li><li><strong>FR-6 (숨김 표시)</strong>: 비표시 메뉴는 트리에서 시각적으로 구분(흐림/아이콘)되고, 사용자 네비게이션에 노출되지 않는다.</li><li><strong>FR-7 (세분 권한 매트릭스 화면)</strong>: 메뉴 권한은 <strong>별도 화면</strong>에서 역할 선택 후 메뉴×권한 (읽기/생성/수정/삭제/Extra1~5)을 매트릭스로 편집·저장한다.</li><li><strong>FR-8 (권한 딥링크)</strong>: 역할 관리에서 특정 역할의 권한 편집으로 진입하면 권한 화면에 그 역할이 미리 선택된다.</li><li><strong>FR-9 (네비 반영)</strong>: 메뉴 생성·수정·삭제·정렬·표시 변경은 좌측 동적 네비게이션에 반영된다.</li><li><strong>FR-10 (백엔드 모델 확장)</strong>: 메뉴 엔터티는 <strong>코드·컴포넌트·표시 여부</strong>를, 역할-메뉴 권한은 <strong>다종 권한 플래그</strong>를 표현·저장할 수 있다. 기존 데이터는 무손실로 이행된다.</li></ul><h3 id="비기능-non-functional" tabindex="-1">비기능 (Non-functional) <a class="header-anchor" href="#비기능-non-functional" aria-label="Permalink to &quot;비기능 (Non-functional)&quot;">​</a></h3><ul><li><strong>FR-11 (시각 일관성)</strong>: 색·간격·컴포넌트·상호작용이 lego 및 이미 정합된 다른 관리 화면과 일관된다.</li><li><strong>FR-12 (응답성·상태표시)</strong>: 로딩/빈/오류 상태가 명확하고, 트리·매트릭스가 일반 규모 데이터에서 체감 지연 없이 동작한다.</li><li><strong>FR-13 (권한 통제 일치·회귀 안전)</strong>: 화면·API 동작은 백엔드 권한 통제와 일치하며, 메뉴/권한 모델 확장이 <strong>기존 인증·메뉴 접근통제·다른 기능의 회귀를 일으키지 않는다.</strong></li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>메뉴(Menu)</strong>: 식별자, 상위, 이름, <strong>코드</strong>, 유형(그룹/메뉴), 경로, <strong>컴포넌트</strong>, 아이콘, 정렬, <strong>표시 여부</strong>, 계층(children).</li><li><strong>역할-메뉴 권한(Role-Menu Permission)</strong>: 역할 × 메뉴별 <strong>다종 권한 플래그</strong>(읽기·생성· 수정·삭제·Extra1~5).</li></ul><h2 id="contracts-api-그래프-인터페이스" tabindex="-1">Contracts (API / 그래프 인터페이스) <a class="header-anchor" href="#contracts-api-그래프-인터페이스" aria-label="Permalink to &quot;Contracts (API / 그래프 인터페이스)&quot;">​</a></h2><p>메뉴 도메인 백엔드를 확장한다(다른 도메인 무변경). 대상:</p><ul><li>메뉴 트리/단건/CRUD: <code>GET /api/v1/menus</code>, <code>GET /api/v1/menus/{id}</code>, <code>POST/PUT/DELETE /api/v1/menus/{id}</code> — 요청/응답에 <strong>코드·컴포넌트·표시 여부</strong> 포함.</li><li><strong>순서 변경(신규)</strong>: 형제 노드의 정렬을 일괄 갱신하는 배치 엔드포인트 (예: <code>PUT /api/v1/menus/reorder</code> — <code>[{id, sortOrder}]</code>).</li><li>역할 권한(확장): <code>GET/PUT /api/v1/menus/roles/{roleId}/permissions</code> — <strong>다종 권한 플래그</strong>(읽기/생성/수정/삭제/Extra1~5)를 주고받는다.</li><li>동적 네비: <code>GET /api/v1/menus/my</code> — 표시 여부·권한 반영.</li></ul><blockquote><p>정확한 컬럼/이행 설계(현행 <code>MENU_TYPE</code>(GROUP/MENU)·<code>USE_YN</code> 과 lego 의 코드/표시 개념 정합, 권한 플래그 컬럼 추가, 데이터 마이그레이션)는 plan 단계에서 확정한다.</p></blockquote><h2 id="assumptions-정보-기반-결정" tabindex="-1">Assumptions (정보 기반 결정) <a class="header-anchor" href="#assumptions-정보-기반-결정" aria-label="Permalink to &quot;Assumptions (정보 기반 결정)&quot;">​</a></h2><ul><li><strong>백엔드 확장 허용(확정, B)</strong>: feature 004 의 메뉴/권한 모델·API 를 lego 수준으로 확장한다. 기존 컬럼(<code>MENU_TYPE</code> GROUP/MENU, <code>USE_YN</code>)은 lego 의 그룹/메뉴·표시 여부 개념과 정합시키고, 코드·컴포넌트·다종 권한 플래그는 신설한다. 기존 데이터 무손실 이행.</li><li><strong>권한 화면 분리</strong>: 권한 편집을 메뉴 트리 화면에서 분리해 <strong>별도 라우트/화면</strong>으로 둔다 (lego 동일). 역할 관리 → 권한 편집 딥링크 제공.</li><li><strong>회귀 안전 우선</strong>: 메뉴 접근통제(SYS_ROLE_MENU 기반)·기존 테스트 통과를 유지하며 확장한다.</li><li><strong>언어</strong>: 한국어 1차.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 메뉴 관리 화면이 lego 와 동일한 <strong>2분할(트리+편집) 구성</strong>으로 보이고 동작한다.</li><li><strong>SC-2</strong>: 관리자가 <strong>드래그앤드롭 또는 이동 버튼</strong>으로 형제 메뉴 순서를 바꾸면 저장되고 좌측 네비게이션 노출 순서에 반영된다.</li><li><strong>SC-3</strong>: 노드를 선택→(코드·컴포넌트·표시 여부 포함) 편집→저장하는 전 과정을 <strong>화면만으로</strong> 끝낼 수 있고, 잘못된 입력은 저장 전에 막힌다.</li><li><strong>SC-4</strong>: 비표시 메뉴가 트리에서 구분되고 사용자 네비게이션에 노출되지 않는다.</li><li><strong>SC-5</strong>: 메뉴 권한을 <strong>별도 화면의 다종 권한 매트릭스</strong>(읽기/생성/수정/삭제/Extra1~5)에서 역할 선택→편집→저장으로 완료하고, 역할 관리 딥링크 진입 시 역할이 미리 선택된다.</li><li><strong>SC-6</strong>: 메뉴 관리 화면의 색·간격·상호작용이 lego 및 다른 관리 화면과 <strong>시각적으로 구분되지 않는다</strong>.</li><li><strong>SC-7</strong>: 메뉴/권한 모델 확장 후에도 <strong>기존 인증·메뉴 접근통제·다른 기능 테스트가 회귀 없이 통과</strong>한다(데이터 무손실 이행 포함).</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><p>남은 차단 결정 없음 — <code>/speckit-plan</code> 진행 가능. (백엔드 변경 범위 = B 확정, 권한 컬럼 = 다종 확정. 세부 컬럼/마이그레이션 설계는 plan 에서.)</p>',33)])])}const p=t(e,[["render",i]]);export{h as __pageData,p as default};
